'use client';

import { useState, useEffect } from 'react';
import { tenant } from "@/config/tenant";
import { formatCurrency } from "@/utils/format";
import { User, Phone, Scissors, Calendar, Clock, CheckCircle2 } from 'lucide-react';
import { api } from '@/services/api';

export default function BookingPage() {
  const [services, setServices] = useState<any[]>([]);
  const [professionals, setProfessionals] = useState<any[]>([]);
  const [selectedService, setSelectedService] = useState<any | null>(null);
  const [selectedProfessional, setSelectedProfessional] = useState<any | null>(null);
  const [name, setName] = useState("");
  const [phone, setPhone] = useState("");
  const [date, setDate] = useState("");
  const [time, setTime] = useState("");
  const [availableSlots, setAvailableSlots] = useState<string[]>([]);
  const [businessHours, setBusinessHours] = useState<any[]>([]);
  const [isBooking, setIsBooking] = useState(false);
  const [isSuccess, setIsSuccess] = useState(false);
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    fetchData();
  }, []);

  const fetchData = async () => {
    setIsLoading(true);
    try {
      const [servs, profs, hours] = await Promise.all([
        api.getServices(tenant.slug),
        api.getProfessionals(tenant.slug),
        api.getBusinessHours(tenant.slug)
      ]);
      if (servs) setServices(servs);
      if (hours) setBusinessHours(hours);
      if (profs && profs.length > 0) {
        setProfessionals(profs);
        setSelectedProfessional(profs[0]);
      }
    } catch (e) {
      console.error(e);
    } finally {
      setIsLoading(false);
    }
  };

  const generateTimeSlots = (rangeStr: string) => {
    if (!rangeStr || rangeStr === 'FECHADO') return [];

    // Suporta vários tipos de traços (hífen, en-dash, em-dash) e normaliza
    const normalizedRange = rangeStr.replace(/[—–-]/g, '|');
    if (!normalizedRange.includes('|')) return [];

    const [start, end] = normalizedRange.split('|').map(t => t.trim());
    const slots: string[] = [];

    let current = new Date(`2024-01-01T${start}:00`);
    const limit = new Date(`2024-01-01T${end}:00`);

    while (current < limit) {
      const hours = current.getHours().toString().padStart(2, '0');
      const minutes = current.getMinutes().toString().padStart(2, '0');
      slots.push(`${hours}:${minutes}`);
      current.setMinutes(current.getMinutes() + 30);
    }

    return slots;
  };

  useEffect(() => {
    if (date && businessHours.length > 0) {
      const selectedDate = new Date(date + 'T00:00:00');
      const dayOfWeek = selectedDate.getDay(); // 0 = Sunday, 1 = Monday...

      // Mapeamento simples baseado nos labels padrão
      // Ajustável se os labels mudarem drasticamente
      let dayRange;
      if (dayOfWeek === 0) {
        dayRange = businessHours.find(h => h.label.toLowerCase().includes('domingo'));
      } else if (dayOfWeek === 6) {
        dayRange = businessHours.find(h => h.label.toLowerCase().includes('sábado') || h.label.toLowerCase().includes('sabado'));
      } else {
        dayRange = businessHours.find(h => h.label.toLowerCase().includes('segunda') || h.label.toLowerCase().includes('sexta'));
      }

      const slots = dayRange ? generateTimeSlots(dayRange.time) : [];
      setAvailableSlots(slots);
      if (slots.length > 0) setTime(slots[0]);
      else setTime("");
    }
  }, [date, businessHours]);

  const handleConfirm = async () => {
    if (!selectedService || !selectedProfessional) return;
    setIsBooking(true);
    try {
      await api.createAppointment(tenant.slug, {
        client_name: name,
        service: selectedService.name,
        time: time,
        duration: `${selectedService.duration_minutes} MIN`,
        status: 'AGENDADO'
      });
      setIsSuccess(true);
    } catch(e) {
      console.error("Erro ao agendar", e);
    } finally {
      setIsBooking(false);
    }
  };

  if (isLoading) {
    return (
      <main className="min-h-screen bg-surface flex items-center justify-center p-6 text-center">
        <div className="w-10 h-10 border-4 border-slate-200 border-t-amber-600 rounded-full animate-spin"></div>
      </main>
    );
  }

  if (isSuccess) {
    return (
      <main className="min-h-screen bg-surface flex flex-col items-center justify-center p-6 text-center space-y-6">
        <div className="w-24 h-24 bg-emerald-100 text-emerald-600 rounded-full flex items-center justify-center shadow-xl shadow-emerald-500/20 animate-bounce">
          <CheckCircle2 size={48} strokeWidth={3} />
        </div>
        <div className="space-y-2">
          <h2 className="text-3xl font-black text-slate-900 tracking-tight">Agendamento Realizado!</h2>
          <p className="text-slate-500 font-medium">Sua experiência foi reservada com sucesso.</p>
        </div>
        <button 
          onClick={() => window.location.href = '/'}
          className="w-full max-w-xs bg-slate-950 text-white py-4 rounded-2xl font-black text-lg shadow-xl shadow-slate-950/20 active:scale-95 transition-all"
        >
          Voltar para Início
        </button>
      </main>
    );
  }

  return (
    <main className="min-h-screen bg-surface p-6 pb-32 max-w-lg mx-auto space-y-8">

      {/* 1. Título e Subtítulo */}
      <header className="space-y-1">
        <h1 className="text-3xl font-black text-slate-900 tracking-tight">Agende sua experiência</h1>
        <p className="text-slate-500 font-medium">Personalize seu atendimento.</p>
      </header>

      {/* 2. Inputs de Contato */}
      <section className="space-y-4">
        <div className="relative">
          <span className="absolute inset-y-0 left-4 flex items-center text-slate-400">
            <User size={18} />
          </span>
          <input 
            type="text" 
            placeholder="Seu nome completo"
            className="w-full pl-12 pr-4 py-4 bg-white rounded-2xl border border-slate-100 shadow-stitch outline-none focus:ring-2 focus:ring-brand-500 transition-all font-medium"
            value={name}
            onChange={(e) => setName(e.target.value)}
          />
        </div>
        <div className="relative">
          <span className="absolute inset-y-0 left-4 flex items-center text-slate-400">
            <Phone size={18} />
          </span>
          <input 
            type="tel" 
            placeholder="Telefone de contato"
            className="w-full pl-12 pr-4 py-4 bg-white rounded-2xl border border-slate-100 shadow-stitch outline-none focus:ring-2 focus:ring-brand-500 transition-all font-medium"
            value={phone}
            onChange={(e) => setPhone(e.target.value)}
          />
        </div>
      </section>

      {/* 3. Seleção de Serviço (Dropdown) */}
      <section className="space-y-3">
        <label className="text-sm font-bold text-slate-400 uppercase tracking-widest ml-1">Selecione o Serviço</label>
        <div className="relative">
          <span className="absolute inset-y-0 left-4 flex items-center text-brand-600">
            <Scissors size={18} />
          </span>
          <select 
            value={selectedService?.id || ""} // Garante que volte ao placeholder se necessário
            onChange={(e) => {
              const service = services.find(s => s.id === e.target.value);
              if (service) setSelectedService(service);
            }}
            className="w-full pl-12 pr-4 py-4 bg-white rounded-2xl border border-slate-100 shadow-stitch outline-none appearance-none font-bold text-slate-800"
          >
            <option value="" disabled>Selecione o Serviço</option>
            {services.map(service => (
              <option key={service.id} value={service.id}>
                {service.name}
              </option>
            ))}
          </select>
        </div>
      </section>

      {/* 4. Data e Horário */}
      <section className="grid grid-cols-2 gap-4">
        <div className="space-y-2">
          <label className="text-[10px] font-black text-slate-400 uppercase tracking-tighter ml-1">Data</label>
          <div className="relative">
            <input 
              type="date" 
              className="w-full p-4 bg-white rounded-2xl border border-slate-100 shadow-stitch text-sm font-bold outline-none" 
              value={date}
              onChange={(e) => setDate(e.target.value)}
            />
          </div>
        </div>
        <div className="space-y-2">
          <label className="text-[10px] font-black text-slate-400 uppercase tracking-tighter ml-1">Horário</label>
          <select 
            className="w-full p-4 bg-white rounded-2xl border border-slate-100 shadow-stitch text-sm font-bold outline-none appearance-none disabled:opacity-50"
            value={time}
            onChange={(e) => setTime(e.target.value)}
            disabled={availableSlots.length === 0}
          >
            {availableSlots.length > 0 ? (
              availableSlots.map(slot => (
                <option key={slot} value={slot}>{slot}</option>
              ))
            ) : (
              <option value="">Indisponível</option>
            )}
          </select>
        </div>
      </section>

      {/* 5. Profissionais Disponíveis */}
      <section className="space-y-4">
        <label className="text-sm font-bold text-slate-400 uppercase tracking-widest ml-1">Profissional</label>
        <div className="flex gap-4 overflow-x-auto pb-2 no-scrollbar">
          {professionals.map(pro => (
            <button 
              key={pro.id}
              onClick={() => setSelectedProfessional(pro)}
              className={`flex-shrink-0 flex items-center gap-3 p-3 rounded-2xl border transition-all ${selectedProfessional?.id === pro.id ? 'bg-brand-50 border-brand-500 ring-1 ring-brand-500' : 'bg-white border-slate-100 shadow-stitch'}`}
            >
              <div className={`w-10 h-10 rounded-xl flex items-center justify-center font-black text-lg ${selectedProfessional?.id === pro.id ? 'bg-brand-500 text-white' : 'bg-slate-100 text-slate-400'}`}>
                {pro.name.charAt(0)}
              </div>
              <div className="text-left">
                <p className="text-sm font-bold text-slate-900 leading-tight">{pro.name}</p>
                <p className="text-[10px] text-slate-500 font-medium">{pro.role}</p>
              </div>
              {selectedProfessional?.id === pro.id && <CheckCircle2 size={16} className="text-brand-600" />}
            </button>
          ))}
        </div>
      </section>

      {/* 6. Resumo e Valor Final */}
      <footer className="fixed bottom-20 left-0 right-0 p-6 bg-white/80 backdrop-blur-xl border-t border-slate-100 max-w-lg mx-auto rounded-t-4xl shadow-2xl">
        {selectedService && (
          <div className="flex justify-between items-center mb-4">
            <div className="flex items-center gap-2">
              <div className="p-2 bg-brand-50 text-brand-600 rounded-lg">
                <Clock size={20} />
              </div>
              <div>
                <p className="text-[10px] font-black text-slate-400 uppercase tracking-tighter leading-none">Tempo Médio</p>
                <p className="font-bold text-slate-900">{selectedService.duration_minutes} min</p>
              </div>
            </div>
            <div className="text-right">
              <p className="text-[10px] font-black text-slate-400 uppercase tracking-tighter leading-none">Valor Total</p>
              <p className="text-2xl font-black text-brand-600">{formatCurrency(selectedService.price)}</p>
            </div>
          </div>
        )}
        {!selectedService && (
          <div className="flex justify-center items-center mb-4 min-h-[48px]">
             <p className="text-slate-400 font-bold text-sm">Selecione um serviço para continuar</p>
          </div>
        )}
        <button 
          disabled={!selectedService || !name || !date || isBooking}
          onClick={handleConfirm}
          className={`w-full py-4 rounded-2xl font-black shadow-lg active:scale-95 disabled:opacity-50 disabled:grayscale transition-all flex items-center justify-center gap-2
            ${isBooking ? 'bg-slate-100 text-slate-400' : 'bg-linear-to-r from-brand-500 to-brand-600 text-white shadow-brand-500/20'}
          `}
        >
          {isBooking ? (
            <div className="w-5 h-5 border-2 border-slate-300 border-t-slate-600 rounded-full animate-spin" />
          ) : 'Confirmar Agendamento'}
        </button>
      </footer>

    </main>
  );
}

'use client';

import { useState } from 'react';
import { tenant } from "@/config/tenant";
import { AppHeader } from "@/components/navigation/AppHeader";
import { formatCurrency } from "@/utils/format";
import { TrendingUp, Calendar, ArrowUpRight, Award } from "lucide-react";

export default function AnalyticsPage() {
  const [period, setPeriod] = useState('Semana');
  const maxValue = Math.max(...tenant.financialData.weeklyStats.map(s => s.value));

  return (
    <main className="min-h-screen bg-surface pb-32">
      <AppHeader />

      <div className="px-6 space-y-8">
        {/* Título e Seletor de Período */}
        <header className="flex justify-between items-center">
          <div className="space-y-1">
            <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Financeiro</p>
            <h2 className="text-3xl font-black text-slate-900 tracking-tight">Análises</h2>
          </div>
          <div className="flex bg-white p-1 rounded-xl border border-slate-100 shadow-sm">
            {['Semana', 'Mês'].map((p) => (
              <button
                key={p}
                onClick={() => setPeriod(p)}
                className={`px-4 py-1.5 rounded-lg text-[10px] font-black transition-all ${
                  period === p ? 'bg-amber-600 text-white shadow-md' : 'text-slate-400'
                }`}
              >
                {p}
              </button>
            ))}
          </div>
        </header>

        {/* Card de Receita Total */}
        <section className="bg-linear-to-br from-amber-500 to-amber-600 p-6 rounded-4xl shadow-xl shadow-amber-600/20 text-white relative overflow-hidden">
          <div className="relative z-10 space-y-1">
            <p className="text-xs font-bold uppercase tracking-widest opacity-80">Receita Total ({period})</p>
            <div className="flex items-baseline gap-2">
              <span className="text-xl font-bold opacity-90">R$</span>
              <h3 className="text-4xl font-black tracking-tighter">
                {tenant.financialData.totalMonth.toLocaleString('pt-BR')}
              </h3>
            </div>
            <div className="inline-flex items-center gap-1 bg-white/20 px-2 py-1 rounded-lg text-[10px] font-black">
              <ArrowUpRight size={14} />
              +{tenant.financialData.growthPercent}% vs período anterior
            </div>
          </div>
          {/* Círculo decorativo ao fundo */}
          <div className="absolute -right-8 -bottom-8 w-32 h-32 bg-white/10 rounded-full blur-2xl" />
        </section>

        {/* Gráfico de Barras Minimalista (CSS Native) */}
        <section className="bg-white p-6 rounded-3xl border border-slate-100 shadow-stitch space-y-6">
          <div className="flex justify-between items-center">
            <h4 className="font-bold text-slate-800">Desempenho Diário</h4>
            <TrendingUp size={18} className="text-emerald-500" />
          </div>

          <div className="flex items-end justify-between h-40 gap-2 pt-4">
            {tenant.financialData.weeklyStats.map((stat, idx) => (
              <div key={idx} className="flex-1 flex flex-col items-center gap-3 group">
                {/* Tooltip simples no hover */}
                <div className="h-full w-full bg-slate-50 rounded-t-xl relative flex items-end overflow-hidden">
                  <div 
                    className={`w-full rounded-t-lg transition-all duration-700 ease-out ${
                      stat.day === 'Ter' ? 'bg-amber-500' : 'bg-slate-200 group-hover:bg-slate-300'
                    }`}
                    style={{ height: `${(stat.value / maxValue) * 100}%` }}
                  />
                </div>
                <span className="text-[10px] font-bold text-slate-400 uppercase">{stat.day}</span>
              </div>
            ))}
          </div>
        </section>

        {/* Ranking de Serviços */}
        <section className="space-y-4">
          <div className="flex items-center gap-2 px-1">
            <Award size={20} className="text-amber-600" />
            <h4 className="font-bold text-slate-800">Serviços mais Rentáveis</h4>
          </div>

          <div className="space-y-3">
            {tenant.financialData.topServices.map((service, idx) => (
              <div key={idx} className="bg-white p-4 rounded-2xl border border-slate-100 shadow-sm flex items-center justify-between">
                <div className="flex items-center gap-3">
                  <div className="w-8 h-8 rounded-full bg-slate-100 flex items-center justify-center font-black text-xs text-slate-400">
                    #{idx + 1}
                  </div>
                  <div>
                    <p className="font-bold text-slate-900 text-sm">{service.name}</p>
                    <p className="text-[10px] font-bold text-slate-400 uppercase">{service.count} atendimentos</p>
                  </div>
                </div>
                <p className="font-black text-slate-900">{formatCurrency(service.total)}</p>
              </div>
            ))}
          </div>
        </section>
      </div>
    </main>
  );
}

'use client';

import { tenant } from "@/config/tenant";
import { AppHeader } from "@/components/navigation/AppHeader";
import { formatCurrency } from "@/utils/format";
import { Clock, Scissors, Users, Plus, Check, X, User, Trash2 } from "lucide-react";
import { useState, useEffect } from "react";
import { api } from "@/services/api";

export default function SettingsPage() {
  const [professionals, setProfessionals] = useState<any[]>([]);
  const [services, setServices] = useState<any[]>([]);
  const [businessHours, setBusinessHours] = useState<any[]>([]);
  const [logoUrl, setLogoUrl] = useState('');
  const [whatsapp, setWhatsapp] = useState('');
  const [companyName, setCompanyName] = useState(tenant.name);
  const [isLoading, setIsLoading] = useState(true);

  const [isAdding, setIsAdding] = useState(false);
  const [isAddingService, setIsAddingService] = useState(false);
  const [isSaving, setIsSaving] = useState(false);
  const [isEditingHours, setIsEditingHours] = useState(false);

  const [newName, setNewName] = useState("");
  const [newSurname, setNewSurname] = useState("");
  const [newRole, setNewRole] = useState("");

  const [newServiceName, setNewServiceName] = useState("");
  const [newServicePrice, setNewServicePrice] = useState("");
  const [newServiceDuration, setNewServiceDuration] = useState("30");

  useEffect(() => {
    fetchData();
  }, []);

  const fetchData = async () => {
    setIsLoading(true);
    try {
      const [setts, servs, profs, hours] = await Promise.all([
        api.getSettings(tenant.slug),
        api.getServices(tenant.slug),
        api.getProfessionals(tenant.slug),
        api.getBusinessHours(tenant.slug)
      ]);

      if (setts) {
        setWhatsapp(setts.whatsapp_number || '');
        setLogoUrl(setts.logo_url || '');
        setCompanyName(setts.name || tenant.name);
      }
      if (servs) setServices(servs);
      if (profs) setProfessionals(profs);
      if (hours && hours.length > 0) setBusinessHours(hours);
    } catch (e) {
      console.error("Erro ao carregar configurações", e);
    } finally {
      setIsLoading(false);
    }
  };

  const handleAddService = async () => {
    if (newServiceName && newServicePrice) {
      try {
        const newService = await api.createService(tenant.slug, {
          name: newServiceName,
          price: parseFloat(newServicePrice),
          duration_minutes: parseInt(newServiceDuration),
        });
        setServices([...services, newService]);
        setIsAddingService(false);
        setNewServiceName("");
        setNewServicePrice("");
        setNewServiceDuration("30");
      } catch (e) {
        console.error("Erro ao adicionar serviço", e);
      }
    }
  };

  const handleUpdateHour = (index: number, field: 'time' | 'closed', value: any) => {
    const updated = [...businessHours];
    updated[index] = { ...updated[index], [field]: value };
    if (field === 'closed' && value === true) {
      updated[index].time = 'FECHADO';
    } else if (field === 'closed' && value === false && updated[index].time === 'FECHADO') {
      updated[index].time = '09:00 — 18:00';
    }
    setBusinessHours(updated);
  };

  const handleRemoveService = async (id: string) => {
    try {
      await api.deleteService(id);
      setServices(services.filter(s => s.id !== id));
    } catch (e) {
      console.error("Erro ao remover serviço", e);
    }
  };

  const handleSave = async () => {
    setIsSaving(true);
    try {
      await api.updateSettings(tenant.slug, { whatsapp_number: whatsapp });
      // Salva os horários que possuem IDs
      for (const h of businessHours) {
        if (h.id) {
          await api.updateBusinessHour(h.id, { time: h.time, closed: h.closed });
        }
      }
    } catch (e) {
      console.error("Erro ao salvar", e);
    } finally {
      setIsSaving(false);
    }
  };

  const handleAddProfessional = async () => {
    if (newName && newRole) {
      try {
        const fullName = `${newName} ${newSurname}`.trim();
        const newProfessional = await api.createProfessional(tenant.slug, {
          name: fullName,
          role: newRole,
          image_url: '',
        });
        setProfessionals([...professionals, newProfessional]);
        setIsAdding(false);
        setNewName("");
        setNewSurname("");
        setNewRole("");
      } catch (e) {
        console.error("Erro ao adicionar profissional", e);
      }
    }
  };

  const handleRemoveProfessional = async (id: string) => {
    try {
      await api.deleteProfessional(id);
      setProfessionals(professionals.filter(p => p.id !== id));
    } catch (e) {
      console.error("Erro ao remover profissional", e);
    }
  };

  if (isLoading) return (
    <main className="min-h-screen bg-surface flex items-center justify-center">
      <p className="text-slate-400 font-bold uppercase tracking-widest animate-pulse">Carregando Painel...</p>
    </main>
  );

  return (
    <main className="min-h-screen bg-surface pb-32">
      <AppHeader />

      <div className="px-6 space-y-8">
        {/* Título da Página */}
        <header className="space-y-1">
          <p className="text-[10px] font-bold text-slate-400 uppercase tracking-[0.2em]">Gerenciamento</p>
          <div className="flex justify-between items-center">
            <h2 className="text-4xl font-black text-slate-900 tracking-tight">Configurações</h2>
          </div>
        </header>

        {/* 0. Informações da Empresa */}
        <section className="bg-white p-6 rounded-3xl border border-slate-100 shadow-stitch space-y-6">
          <div className="flex items-center gap-4">
            <div className="relative w-16 h-16 bg-slate-50 rounded-2xl overflow-hidden border border-slate-100 group">
              <img src={logoUrl || '/next.svg'} alt="Logo" className="w-full h-full object-cover" />
              <div className="absolute inset-0 bg-black/40 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity cursor-pointer">
                 <p className="text-[8px] text-white font-bold uppercase">Mudar</p>
              </div>
            </div>
            <div className="flex-1 space-y-1">
              <h3 className="font-bold text-slate-900 leading-none">{companyName}</h3>
              <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest leading-none">Perfil Comercial</p>
            </div>
          </div>

          <div className="grid grid-cols-1 gap-4">
            <div className="space-y-1.5">
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">WhatsApp de Contato</label>
              <input 
                type="text" 
                className="w-full bg-slate-50 border border-slate-100 rounded-xl px-4 py-3 text-sm font-bold text-slate-700 outline-none focus:border-amber-500 transition-colors"
                value={whatsapp}
                onChange={(e) => setWhatsapp(e.target.value)}
                placeholder="Ex: 5511999999999"
              />
            </div>
          </div>
        </section>

        {/* 1. Horário de Funcionamento */}
        <section className="space-y-4">
          <div className="flex justify-between items-center">
            <div className="flex items-center gap-2">
              <div className="p-2 bg-amber-100 text-amber-600 rounded-lg">
                <Clock size={20} />
              </div>
              <h3 className="font-bold text-slate-800">Horário de Funcionamento</h3>
            </div>
            <button 
              onClick={() => setIsEditingHours(true)}
              className="text-[10px] font-black text-slate-400 uppercase tracking-widest hover:text-amber-600 transition-colors"
            >
              Editar
            </button>
          </div>

          <div className="bg-slate-50 p-6 rounded-3xl border border-slate-100 space-y-4">
            {businessHours.map((item, idx) => (
              <div key={idx} className="flex justify-between items-center text-sm">
                <span className="font-semibold text-slate-500">{item.label}</span>
                <span className={`font-bold ${item.closed ? 'text-amber-500 italic uppercase' : 'text-slate-900'}`}>
                  {item.time}
                </span>
              </div>
            ))}
          </div>
        </section>

        {/* 2. Serviços & Preços */}
        <section className="space-y-4">
          <div className="flex justify-between items-center">
            <div className="flex items-center gap-2">
              <div className="p-2 bg-amber-100 text-amber-600 rounded-lg">
                <Scissors size={20} />
              </div>
              <h3 className="font-bold text-slate-800">Serviços & Preços</h3>
            </div>
            <button 
              onClick={() => setIsAddingService(!isAddingService)}
              className="w-8 h-8 bg-amber-700 text-white rounded-full flex items-center justify-center shadow-lg shadow-amber-900/20 active:scale-90 transition-transform"
            >
              <Plus size={18} strokeWidth={3} />
            </button>
          </div>

          {isAddingService && (
             <div className="bg-amber-50 p-5 rounded-2xl border border-amber-100 space-y-4 animate-in fade-in slide-in-from-top-4 duration-300">
                <div className="space-y-3">
                  <input 
                    type="text" 
                    placeholder="Nome do Serviço"
                    className="w-full text-sm font-bold p-3 bg-white rounded-xl border border-amber-100 outline-none focus:ring-2 focus:ring-amber-500/20"
                    value={newServiceName}
                    onChange={(e) => setNewServiceName(e.target.value)}
                  />
                  <div className="grid grid-cols-2 gap-3">
                    <input 
                      type="number" 
                      placeholder="Preço (R$)"
                      className="w-full text-sm font-bold p-3 bg-white rounded-xl border border-amber-100 outline-none"
                      value={newServicePrice}
                      onChange={(e) => setNewServicePrice(e.target.value)}
                    />
                    <select 
                      className="w-full text-sm font-bold p-3 bg-white rounded-xl border border-amber-100 outline-none"
                      value={newServiceDuration}
                      onChange={(e) => setNewServiceDuration(e.target.value)}
                    >
                      <option value="30">30 min</option>
                      <option value="45">45 min</option>
                      <option value="60">60 min</option>
                      <option value="90">90 min</option>
                    </select>
                  </div>
                </div>
                <div className="flex gap-2">
                    <button 
                      onClick={handleAddService}
                      className="flex-1 bg-amber-600 text-white py-3 rounded-xl font-bold flex items-center justify-center hover:bg-amber-700 transition-colors"
                    >
                      Salvar Serviço
                    </button>
                    <button 
                      onClick={() => setIsAddingService(false)}
                      className="px-4 bg-white text-slate-400 rounded-xl hover:bg-slate-50 transition-colors"
                    >
                      <X size={20} />
                    </button>
                  </div>
             </div>
          )}

          <div className="space-y-3">
            {services.map((service, idx) => (
              <div key={service.id} className="bg-white p-5 rounded-2xl border border-slate-100 shadow-stitch flex items-center gap-4 relative overflow-hidden group">
                {/* Barrinha lateral colorida como no modelo */}
                <div className={`absolute left-0 top-4 bottom-4 w-1 rounded-r-full ${
                  idx === 0 ? 'bg-amber-300' : idx === 1 ? 'bg-indigo-200' : 'bg-stone-300'
                }`} />

                <div className="flex-1 ml-2">
                  <h4 className="font-bold text-slate-900">{service.name}</h4>
                  <p className="text-[10px] font-bold text-slate-400 uppercase tracking-tight">{service.duration_minutes} MINUTOS</p>
                </div>
                <div className="text-right flex items-center gap-3">
                  <p className="text-lg font-black text-amber-700">{formatCurrency(service.price)}</p>
                  <button 
                    onClick={() => handleRemoveService(service.id)}
                    className="p-1.5 text-slate-300 hover:text-red-400 transition-colors"
                    title="Remover serviço"
                  >
                    <Trash2 size={16} />
                  </button>
                </div>
              </div>
            ))}
          </div>
        </section>

        {/* 3. Profissionais */}
        <section className="space-y-4">
          <div className="flex justify-between items-center">
            <div className="flex items-center gap-2">
              <div className="p-2 bg-amber-100 text-amber-600 rounded-lg">
                <Users size={20} />
              </div>
              <h3 className="font-bold text-slate-800">Profissionais</h3>
            </div>
            <button 
              onClick={() => setIsAdding(!isAdding)}
              className="w-8 h-8 bg-amber-700 text-white rounded-full flex items-center justify-center shadow-lg shadow-amber-900/20 active:scale-90 transition-transform"
            >
              <Plus size={18} strokeWidth={3} />
            </button>
          </div>

          <div className="flex gap-4 overflow-x-auto no-scrollbar pb-4 -mx-6 px-6">
            {professionals.map((pro) => (
              <div key={pro.id} className="flex-shrink-0 w-48 space-y-3">
                <div className="relative p-5 rounded-3xl bg-slate-50 border border-slate-100 shadow-sm group hover:shadow-md transition-all">
                  <div className="w-12 h-12 rounded-2xl bg-brand-100 text-brand-600 flex items-center justify-center font-black text-xl mb-4">
                    {pro.name.charAt(0)}
                  </div>
                  <p className="font-black text-slate-900 leading-tight text-lg">{pro.name}</p>
                  <p className="text-[10px] uppercase font-bold text-slate-400 tracking-wider mt-1">{pro.role}</p>

                  <button 
                    onClick={() => handleRemoveProfessional(pro.id)}
                    className="absolute top-4 right-4 p-2 bg-white text-slate-400 hover:text-rose-500 hover:bg-rose-50 border border-slate-100 rounded-xl transition-all shadow-sm opacity-0 group-hover:opacity-100"
                    title="Remover profissional"
                  >
                    <Trash2 size={16} />
                  </button>
                </div>
                <div className="text-center">
                   <p className="text-[10px] font-black text-amber-600 uppercase tracking-[0.15em]">{pro.role}</p>
                </div>
              </div>
            ))}

            {isAdding && (
              <div className="flex-shrink-0 w-48 space-y-3">
                <div className="relative h-64 rounded-3xl overflow-hidden shadow-lg bg-slate-100 border-2 border-dashed border-slate-200 flex flex-col items-center justify-center gap-2 text-slate-400">
                  <div className="w-16 h-16 bg-white rounded-full flex items-center justify-center shadow-sm">
                    <User size={32} />
                  </div>
                  <span className="text-[10px] font-bold uppercase tracking-widest">Nova Foto</span>
                </div>
                <div className="space-y-2">
                  <input 
                    type="text" 
                    placeholder="Nome"
                    className="w-full text-xs font-bold p-2 bg-white rounded-xl border border-slate-100 focus:outline-none focus:border-amber-500 transition-colors"
                    value={newName}
                    onChange={(e) => setNewName(e.target.value)}
                  />
                  <input 
                    type="text" 
                    placeholder="Sobrenome"
                    className="w-full text-xs font-bold p-2 bg-white rounded-xl border border-slate-100 focus:outline-none focus:border-amber-500 transition-colors"
                    value={newSurname}
                    onChange={(e) => setNewSurname(e.target.value)}
                  />
                  <input 
                    type="text" 
                    placeholder="Especialidade"
                    className="w-full text-[10px] font-black text-amber-600 uppercase tracking-[0.15em] p-2 bg-white rounded-xl border border-slate-100 focus:outline-none focus:border-amber-500 transition-colors"
                    value={newRole}
                    onChange={(e) => setNewRole(e.target.value)}
                  />
                  <div className="flex gap-2">
                    <button 
                      onClick={handleAddProfessional}
                      className="flex-1 bg-amber-600 text-white p-2 rounded-xl flex items-center justify-center hover:bg-amber-700 transition-colors"
                    >
                      <Check size={18} />
                    </button>
                    <button 
                      onClick={() => setIsAdding(false)}
                      className="flex-1 bg-slate-100 text-slate-500 p-2 rounded-xl flex items-center justify-center hover:bg-slate-200 transition-colors"
                    >
                      <X size={18} />
                    </button>
                  </div>
                </div>
              </div>
            )}
          </div>
        </section>

        {/* Botão de Salvar Alterações */}
        <div className="pt-4">
          <button 
            onClick={handleSave}
            disabled={isSaving}
            className={`w-full py-5 rounded-2xl font-black text-lg shadow-xl active:scale-[0.98] transition-all flex items-center justify-center gap-3
              ${isSaving 
                ? 'bg-emerald-500 text-white shadow-emerald-500/20' 
                : 'bg-linear-to-r from-amber-600 to-amber-500 text-white shadow-amber-600/20'}
            `}
          >
            {isSaving ? (
              <>
                <Check size={24} strokeWidth={3} />
                Salvo com Sucesso!
              </>
            ) : (
              'Salvar Alterações'
            )}
          </button>
        </div>
      </div>

      {/* Modal de Horários */}
      {isEditingHours && (
        <div className="fixed inset-0 z-50 flex items-end justify-center sm:items-center p-0 sm:p-4">
          <div 
            className="absolute inset-0 bg-slate-950/40 backdrop-blur-sm transition-opacity"
            onClick={() => setIsEditingHours(false)}
          />
          <div className="relative w-full max-w-lg bg-white rounded-t-[40px] sm:rounded-3xl shadow-2xl overflow-hidden animate-in fade-in slide-in-from-bottom-10 duration-300">
            <div className="p-8 space-y-6">
              <header className="flex justify-between items-start">
                <div className="space-y-1">
                  <h3 className="text-2xl font-black text-slate-900 tracking-tight">Editar Horários</h3>
                  <p className="text-xs font-medium text-slate-500">Configure os períodos de atendimento.</p>
                </div>
                <button 
                  onClick={() => setIsEditingHours(false)}
                  className="p-2 bg-slate-100 text-slate-400 rounded-xl hover:text-slate-900 transition-colors"
                >
                  <X size={20} />
                </button>
              </header>

              <div className="space-y-4">
                {businessHours.map((item, idx) => (
                  <div key={idx} className="bg-slate-50 p-5 rounded-2xl border border-slate-200 flex items-center justify-between gap-4">
                    <div className="flex-1">
                      <p className="text-sm font-bold text-slate-900">{item.label}</p>
                      <input 
                        type="text" 
                        disabled={item.closed}
                        className={`w-full mt-1 bg-transparent border-b border-slate-200 focus:border-amber-500 focus:outline-none py-1 text-sm font-semibold transition-colors ${item.closed ? 'text-slate-300 italic' : 'text-slate-700'}`}
                        value={item.time}
                        onChange={(e) => handleUpdateHour(idx, 'time', e.target.value)}
                      />
                    </div>
                    <label className="flex items-center gap-2 cursor-pointer select-none">
                      <span className="text-[10px] font-black text-slate-400 uppercase tracking-wider">Fechado</span>
                      <div className="relative inline-flex items-center cursor-pointer">
                        <input 
                          type="checkbox" 
                          className="sr-only peer"
                          checked={item.closed}
                          onChange={(e) => handleUpdateHour(idx, 'closed', e.target.checked)}
                        />
                        <div className="w-11 h-6 bg-slate-200 peer-focus:outline-none rounded-full peer peer-checked:after:translate-x-full peer-checked:after:border-white after:content-[''] after:absolute after:top-[2px] after:left-[2px] after:bg-white after:border-slate-300 after:border after:rounded-full after:h-5 after:w-5 after:transition-all peer-checked:bg-amber-600"></div>
                      </div>
                    </label>
                  </div>
                ))}
              </div>

              <button 
                onClick={() => setIsEditingHours(false)}
                className="w-full bg-slate-950 text-white py-4 rounded-2xl font-black text-lg active:scale-95 transition-all shadow-lg shadow-slate-950/20"
              >
                Confirmar
              </button>
            </div>
          </div>
        </div>
      )}
    </main>
  );
}

'use client';

import { useState, useEffect } from 'react';
import { tenant } from "@/config/tenant";
import { AppHeader } from "@/components/navigation/AppHeader";
import { MoreVertical, Plus, Trash2, Clock, X, Check, Calendar as CalendarIcon, Scissors, User, Settings2 } from "lucide-react";
import Link from 'next/link';
import { formatCurrency } from "@/utils/format";
import { api } from "@/services/api";

export default function AgendaPage() {
  const [appointments, setAppointments] = useState<any[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [activeFilter, setActiveFilter] = useState('TODOS');
  const [activeMenuId, setActiveMenuId] = useState<string | null>(null);
  const [editingApp, setEditingApp] = useState<any | null>(null);
  const [services, setServices] = useState<any[]>([]);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [selectedDay, setSelectedDay] = useState(0); // Index of generated days

  useEffect(() => {
    fetchAppointments();
  }, []);

  const fetchAppointments = async () => {
    setIsLoading(true);
    try {
      const [apps, servs] = await Promise.all([
        api.getAppointments(tenant.slug),
        api.getServices(tenant.slug)
      ]);
      setAppointments(apps || []);
      setServices(servs || []);
    } catch (e) {
      console.error("Erro ao buscar agendamentos", e);
    } finally {
      setIsLoading(false);
    }
  };

  const getDays = () => {
    const today = new Date();
    const result = [];
    const weekDays = ['DOM', 'SEG', 'TER', 'QUA', 'QUI', 'SEX', 'SÁB'];

    for (let i = 0; i < 30; i++) {
      const d = new Date();
      d.setDate(today.getDate() + i);
      result.push({
        label: weekDays[d.getDay()],
        num: d.getDate(),
        fullDate: d
      });
    }
    return result;
  };

  const days = getDays();
  const currentMonth = new Intl.DateTimeFormat('pt-BR', { month: 'long', year: 'numeric' }).format(new Date());

  const handleStatusChange = async (id: string, newStatus: string) => {
    setActiveMenuId(null);
    try {
      // Otimista
      setAppointments(appointments.map(app => app.id === id ? { ...app, status: newStatus } : app));
      await api.updateAppointment(id, { status: newStatus });
    } catch (e) {
      console.error("Erro ao atualizar status", e);
      fetchAppointments(); // Reverte em caso de erro
    }
  };

  const handleUpdateAppointment = async (e: React.FormEvent) => {
    e.preventDefault();
    if (editingApp) {
      setIsModalOpen(false);
      try {
        setAppointments(appointments.map(app => app.id === editingApp.id ? editingApp : app));
        await api.updateAppointment(editingApp.id, {
          time: editingApp.time,
          duration: editingApp.duration,
          service: editingApp.service,
          status: editingApp.status
        });
        setEditingApp(null);
      } catch (e) {
        console.error("Erro ao salvar", e);
        fetchAppointments();
      }
    }
  };

  const handleDeleteAppointment = async (id: string) => {
    setActiveMenuId(null);
    try {
      setAppointments(appointments.filter(app => app.id !== id));
      await api.deleteAppointment(id);
    } catch (e) {
      console.error("Erro ao deletar", e);
      fetchAppointments();
    }
  };

  const filters = ['TODOS', 'AGENDADO', 'REALIZADO', 'CANCELADO'];

  return (
    <main className="min-h-screen bg-surface pb-32">
      <AppHeader />

      <div className="px-6 space-y-6">
        {/* Título e Mês */}
        <div className="flex justify-between items-end">
          <h2 className="text-3xl font-black text-slate-900 tracking-tight">Agendamentos</h2>
          <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-1">{currentMonth}</span>
        </div>

        {/* Calendário Estilo Apple */}
        <div className="flex gap-3 overflow-x-auto no-scrollbar pb-2">
          {days.map((day, idx) => (
            <button
              key={idx}
              onClick={() => setSelectedDay(idx)}
              className={`flex-shrink-0 flex flex-col items-center justify-center w-16 h-20 rounded-2xl transition-all ${
                selectedDay === idx 
                ? 'bg-amber-600 text-white shadow-lg shadow-amber-600/30 scale-105' 
                : 'bg-white text-slate-400 border border-slate-100'
              }`}
            >
              <span className="text-[10px] font-bold uppercase">{day.label}</span>
              <span className="text-xl font-black">{day.num}</span>
            </button>
          ))}
        </div>

        {/* Filtros de Status */}
        <div className="flex gap-2 overflow-x-auto no-scrollbar py-2">
          {filters.map((filter) => (
            <button
              key={filter}
              onClick={() => setActiveFilter(filter)}
              className={`px-6 py-2 rounded-full text-[10px] font-black uppercase tracking-wider transition-all ${
                activeFilter === filter 
                ? 'bg-amber-100 text-amber-700 ring-1 ring-amber-200' 
                : 'bg-slate-100 text-slate-400'
              }`}
            >
              {filter}
            </button>
          ))}
        </div>

        {/* Lista de Cards */}
        <div className="space-y-4">
          {isLoading ? (
            <div className="text-center py-10">
              <p className="text-slate-400 font-bold uppercase text-[10px] tracking-widest animate-pulse">Carregando Agendamentos...</p>
            </div>
          ) : appointments.length === 0 ? (
            <div className="text-center py-10 bg-slate-50 rounded-3xl border border-slate-100">
              <p className="text-slate-400 font-bold uppercase text-[10px] tracking-widest">Nenhum agendamento encontrado</p>
            </div>
          ) : appointments
            .filter(app => activeFilter === 'TODOS' || app.status === activeFilter)
            .map((app) => (
              <div 
                key={app.id} 
                className={`bg-white p-5 rounded-3xl border border-slate-100 shadow-stitch relative flex items-center gap-4`}
              >
                {/* Borda Lateral Colorida por Status */}
                <div className={`absolute left-0 top-4 bottom-4 w-1 rounded-r-full ${
                  app.status === 'AGENDADO' ? 'bg-amber-500' : 
                  app.status === 'REALIZADO' ? 'bg-emerald-500' : 'bg-rose-400'
                }`} />

                <div className="flex-1">
                  <h4 className="font-bold text-slate-900 leading-tight">{app.clientName || app.client_name}</h4>
                  <p className="text-[10px] text-slate-400 font-bold uppercase tracking-tighter">{app.service}</p>

                  {/* Status Pill Interno */}
                  <div className={`mt-3 inline-flex items-center gap-1.5 px-2 py-1 rounded-lg text-[9px] font-black uppercase ${
                    app.status === 'AGENDADO' ? 'bg-amber-50 text-amber-600' : 
                    app.status === 'REALIZADO' ? 'bg-emerald-50 text-emerald-600' : 'bg-rose-50 text-rose-600'
                  }`}>
                    <div className={`w-1.5 h-1.5 rounded-full ${
                      app.status === 'AGENDADO' ? 'bg-amber-500' : 
                      app.status === 'REALIZADO' ? 'bg-emerald-500' : 'bg-rose-400'
                    }`} />
                    {app.status}
                  </div>
                </div>

                <div className="text-right flex flex-col items-end gap-2">
                  <div className="leading-none">
                    <p className="text-lg font-black text-slate-950">{app.time}</p>
                    <p className="text-[9px] font-bold text-slate-400 uppercase">{app.duration}</p>
                  </div>
                  <div className="relative">
                    <button 
                        onClick={(e) => {
                          e.stopPropagation();
                          setActiveMenuId(activeMenuId === app.id ? null : app.id);
                        }}
                        className={`px-3 py-1.5 rounded-xl text-[10px] font-black uppercase tracking-wider transition-all flex items-center gap-1.5 ${
                          activeMenuId === app.id 
                          ? 'bg-slate-900 text-white' 
                          : 'bg-slate-50 text-slate-400 hover:bg-slate-100 hover:text-slate-600'
                        }`}
                    >
                        <Settings2 size={14} />
                        Gerenciar
                    </button>

                    {activeMenuId === app.id && (
                        <>
                        <div className="fixed inset-0 z-[45]" onClick={() => setActiveMenuId(null)} />
                        <div className="absolute right-0 top-full mt-2 w-48 bg-white border border-slate-100 rounded-2xl shadow-2xl z-50 overflow-hidden animate-in fade-in zoom-in-95 duration-200">
                            <div className="px-4 py-2 bg-slate-50 border-b border-slate-100">
                                <p className="text-[8px] font-black text-slate-400 uppercase tracking-widest">Ações do Agendamento</p>
                            </div>
                            <button 
                                onClick={() => {
                                    setEditingApp(app);
                                    setIsModalOpen(true);
                                    setActiveMenuId(null);
                                }}
                                className="w-full text-left px-4 py-3 text-[10px] font-black text-slate-600 uppercase tracking-widest hover:bg-slate-50 border-b border-slate-50 flex items-center gap-2"
                            >
                                <Clock size={14} className="text-blue-500" /> Editar / Reagendar
                            </button>
                            <button 
                                onClick={() => handleStatusChange(app.id, 'REALIZADO')}
                                className="w-full text-left px-4 py-3 text-[10px] font-black text-emerald-600 uppercase tracking-widest hover:bg-emerald-50 border-b border-slate-50 flex items-center gap-2"
                            >
                                <Check size={14} /> Concluir
                            </button>
                            <button 
                                onClick={() => handleStatusChange(app.id, 'CANCELADO')}
                                className="w-full text-left px-4 py-3 text-[10px] font-black text-rose-500 uppercase tracking-widest hover:bg-rose-50 border-b border-slate-50 flex items-center gap-2"
                            >
                                <X size={14} /> Cancelar
                            </button>
                            <button 
                                onClick={() => handleDeleteAppointment(app.id)}
                                className="w-full text-left px-4 py-3 text-[10px] font-black text-slate-400 uppercase tracking-widest hover:bg-slate-50 flex items-center gap-2"
                            >
                                <Trash2 size={14} /> Excluir
                            </button>
                        </div>
                        </>
                    )}
                  </div>
                </div>
              </div>
            ))}
        </div>
      </div>

      {/* Modal de Edição */}
      {isModalOpen && editingApp && (
        <div className="fixed inset-0 z-50 flex items-end justify-center sm:items-center p-0 sm:p-4 animate-in fade-in duration-300">
            <div className="absolute inset-0 bg-slate-950/40 backdrop-blur-sm" onClick={() => setIsModalOpen(false)} />
            <form 
                onSubmit={handleUpdateAppointment}
                className="relative w-full max-w-lg bg-white rounded-t-[40px] sm:rounded-3xl shadow-2xl overflow-hidden animate-in slide-in-from-bottom-20 duration-500"
            >
                <div className="p-8 space-y-8">
                    <header className="flex justify-between items-start">
                        <div className="space-y-1">
                            <h3 className="text-2xl font-black text-slate-900 tracking-tight">Editar Agendamento</h3>
                            <p className="text-xs font-medium text-slate-500">Altere os detalhes do procedimento.</p>
                        </div>
                        <button 
                            type="button"
                            onClick={() => setIsModalOpen(false)}
                            className="p-2 bg-slate-100 text-slate-400 rounded-xl hover:text-slate-900"
                        >
                            <X size={20} />
                        </button>
                    </header>

                    <div className="space-y-5">
                        {/* Status */}
                        <div className="space-y-2">
                            <label className="text-[10px] font-black text-slate-400 uppercase tracking-[0.15em] ml-1">Status do Agendamento</label>
                            <div className="grid grid-cols-3 gap-2">
                                {['AGENDADO', 'REALIZADO', 'CANCELADO'].map(status => (
                                    <button
                                        key={status}
                                        type="button"
                                        onClick={() => setEditingApp({ ...editingApp, status })}
                                        className={`py-3 rounded-xl text-[9px] font-black uppercase tracking-wider transition-all border-2 ${
                                            editingApp.status === status
                                            ? status === 'REALIZADO' ? 'bg-emerald-50 border-emerald-500 text-emerald-700' :
                                              status === 'CANCELADO' ? 'bg-rose-50 border-rose-500 text-rose-700' :
                                              'bg-amber-50 border-amber-500 text-amber-700'
                                            : 'bg-white border-slate-100 text-slate-400'
                                        }`}
                                    >
                                        {status}
                                    </button>
                                ))}
                            </div>
                        </div>

                        {/* Tempo e Horário */}
                        <div className="grid grid-cols-2 gap-4">
                            <div className="space-y-2">
                                <label className="text-[10px] font-black text-slate-400 uppercase tracking-[0.15em] ml-1">Horário</label>
                                <div className="relative">
                                    <span className="absolute inset-y-0 left-4 flex items-center text-slate-400"><Clock size={16} /></span>
                                    <input 
                                        type="text" 
                                        className="w-full pl-10 pr-4 py-3 bg-slate-50 border border-slate-100 rounded-xl text-sm font-bold text-slate-700 outline-none focus:border-amber-500"
                                        value={editingApp.time}
                                        onChange={(e) => setEditingApp({ ...editingApp, time: e.target.value })}
                                    />
                                </div>
                            </div>
                            <div className="space-y-2">
                                <label className="text-[10px] font-black text-slate-400 uppercase tracking-[0.15em] ml-1">Duração</label>
                                <div className="relative">
                                    <span className="absolute inset-y-0 left-4 flex items-center text-slate-400"><CalendarIcon size={16} /></span>
                                    <input 
                                        type="text" 
                                        className="w-full pl-10 pr-4 py-3 bg-slate-50 border border-slate-100 rounded-xl text-sm font-bold text-slate-700 outline-none"
                                        value={editingApp.duration}
                                        onChange={(e) => setEditingApp({ ...editingApp, duration: e.target.value })}
                                    />
                                </div>
                            </div>
                        </div>

                        {/* Serviço */}
                        <div className="space-y-2">
                            <label className="text-[10px] font-black text-slate-400 uppercase tracking-[0.15em] ml-1">Serviço</label>
                            <div className="relative">
                                <span className="absolute inset-y-0 left-4 flex items-center text-slate-400"><Scissors size={16} /></span>
                                <select 
                                    className="w-full pl-10 pr-4 py-3 bg-slate-50 border border-slate-100 rounded-xl text-sm font-bold text-slate-700 outline-none focus:border-amber-500 appearance-none"
                                    value={editingApp.service}
                                    onChange={(e) => setEditingApp({ ...editingApp, service: e.target.value })}
                                >
                                    {services.map(s => (
                                        <option key={s.id} value={s.name}>{s.name} - {formatCurrency(s.price)}</option>
                                    ))}
                                </select>
                            </div>
                        </div>
                    </div>

                    <div className="flex gap-4 pt-4">
                        <button 
                            type="submit"
                            className="flex-1 bg-slate-950 text-white py-4 rounded-2xl font-black text-lg active:scale-95 transition-all shadow-xl shadow-slate-950/20"
                        >
                            Salvar Alterações
                        </button>
                    </div>
                </div>
            </form>
        </div>
      )}

      {/* Floating Action Button (FAB) */}
      <Link href="/agendar" className="fixed bottom-24 right-6 w-14 h-14 bg-amber-600 text-white rounded-full shadow-2xl flex items-center justify-center active:scale-90 transition-transform z-40 border-4 border-white">
        <Plus size={28} strokeWidth={3} />
      </Link>
    </main>
  );
}

